+  private async flushChunk(
+    parts: Uint8Array[],
+    totalSize: number,
+    entries: Array<{ sha: string; offset: number; length: number }>,
+  ): Promise<void> {
+    // Concatenate parts into a single blob
+    const blob = new Uint8Array(totalSize);
